  <text x="100" y="100" fill="#e4e4e7" font-size="13.5" font-weight="700" font-family="sans-serif" text-anchor="middle">2026年末</text>
  <text x="100" y="160" fill="#9a9aa4" font-size="12.5" font-family="sans-serif" text-anchor="middle">省庁横断</text>
